import{_ as e,c as a,o as d,ag as o}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"Android + Kotlin Knowledge Points","description":"","frontmatter":{},"headers":[],"relativePath":"reading-notes/android/android-points.en.md","filePath":"reading-notes/android/android-points.en.md"}'),r={name:"reading-notes/android/android-points.en.md"};function i(n,t,c,h,l,s){return d(),a("div",null,t[0]||(t[0]=[o('<h1 id="android-kotlin-knowledge-points" tabindex="-1">Android + Kotlin Knowledge Points <a class="header-anchor" href="#android-kotlin-knowledge-points" aria-label="Permalink to &quot;Android + Kotlin Knowledge Points&quot;">​</a></h1><p><a href="/reading-notes/android/android-points.html">中文</a></p><p>Knowledge points reference, grouped by Android basics, advanced Android, and Kotlin.</p><hr><h2 id="android-basics" tabindex="-1">Android Basics <a class="header-anchor" href="#android-basics" aria-label="Permalink to &quot;Android Basics&quot;">​</a></h2><h3 id="gestures-touch" tabindex="-1">Gestures &amp; Touch <a class="header-anchor" href="#gestures-touch" aria-label="Permalink to &quot;Gestures &amp; Touch&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Double-tap</td><td><code>GestureDetector</code> + <code>SimpleOnGestureListener.onDoubleTap()</code>; avoid manual time-interval checks</td></tr><tr><td>Pointer count</td><td><code>event.getPointerCount()</code></td></tr></tbody></table><h3 id="lifecycle-visibility" tabindex="-1">Lifecycle &amp; Visibility <a class="header-anchor" href="#lifecycle-visibility" aria-label="Permalink to &quot;Lifecycle &amp; Visibility&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Activity becomes invisible</td><td><code>onStop()</code></td></tr><tr><td>Distinction</td><td><code>onPause()</code> = loses focus but may still be visible</td></tr></tbody></table><h3 id="storage-resources" tabindex="-1">Storage &amp; Resources <a class="header-anchor" href="#storage-resources" aria-label="Permalink to &quot;Storage &amp; Resources&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>SharedPreferences write</td><td>Sync: <code>commit()</code>; async: <code>apply()</code></td></tr><tr><td>Locale resources</td><td>e.g. French: <code>res/values-fr/strings.xml</code></td></tr><tr><td>Launcher icon dir</td><td><code>mipmap</code></td></tr></tbody></table><h3 id="ui-click" tabindex="-1">UI &amp; Click <a class="header-anchor" href="#ui-click" aria-label="Permalink to &quot;UI &amp; Click&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>android:onClick method missing</td><td>Direct crash → <code>IllegalStateException</code> (reflection cannot find method)</td></tr><tr><td>Video playback View</td><td><code>VideoView</code> (not MediaPlayer / SurfaceView)</td></tr></tbody></table><h3 id="sensors" tabindex="-1">Sensors <a class="header-anchor" href="#sensors" aria-label="Permalink to &quot;Sensors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Angular velocity</td><td><code>Sensor.TYPE_GYROSCOPE</code></td></tr><tr><td>Ambient temperature</td><td><code>Sensor.TYPE_AMBIENT_TEMPERATURE</code></td></tr></tbody></table><h3 id="launch-process" tabindex="-1">Launch &amp; Process <a class="header-anchor" href="#launch-process" aria-label="Permalink to &quot;Launch &amp; Process&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Boot complete broadcast</td><td><code>android.intent.action.BOOT_COMPLETED</code>; needs <code>RECEIVE_BOOT_COMPLETED</code> permission</td></tr><tr><td>FLAG_ACTIVITY_SINGLE_TOP</td><td>If Activity is already on top, no new instance; triggers <code>onNewIntent()</code></td></tr><tr><td>Highest process priority</td><td>Foreground process (killed last)</td></tr></tbody></table><hr><h2 id="android-advanced" tabindex="-1">Android Advanced <a class="header-anchor" href="#android-advanced" aria-label="Permalink to &quot;Android Advanced&quot;">​</a></h2><h3 id="window-features" tabindex="-1">Window Features <a class="header-anchor" href="#window-features" aria-label="Permalink to &quot;Window Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>requestWindowFeature valid</td><td><code>FEATURE_NO_TITLE</code>, <code>FEATURE_LEFT_ICON</code>, <code>FEATURE_RIGHT_ICON</code></td></tr><tr><td>Invalid constants</td><td><code>FEATURE_TOP_ICON</code>, <code>FEATURE_NO_ICON</code></td></tr></tbody></table><h3 id="touch-clipboard" tabindex="-1">Touch &amp; Clipboard <a class="header-anchor" href="#touch-clipboard" aria-label="Permalink to &quot;Touch &amp; Clipboard&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>MotionEvent multi-touch</td><td><code>ACTION_POINTER_DOWN</code> / <code>ACTION_POINTER_UP</code></td></tr><tr><td>Clipboard</td><td><code>ClipboardManager</code></td></tr><tr><td>Drag listener</td><td><code>View.OnDragListener</code></td></tr></tbody></table><h3 id="camera-exceptions" tabindex="-1">Camera &amp; Exceptions <a class="header-anchor" href="#camera-exceptions" aria-label="Permalink to &quot;Camera &amp; Exceptions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Camera in use</td><td><code>openCamera</code> → <code>CameraAccessException</code></td></tr></tbody></table><h3 id="threading-async" tabindex="-1">Threading &amp; Async <a class="header-anchor" href="#threading-async" aria-label="Permalink to &quot;Threading &amp; Async&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Thread helpers</td><td><code>ThreadPoolExecutor</code>, <code>HandlerThread</code>, <code>AsyncTask</code> (deprecated), <code>AsyncTaskLoader</code></td></tr><tr><td>Background download survives rotation</td><td>Service (typically foreground)</td></tr></tbody></table><h3 id="other" tabindex="-1">Other <a class="header-anchor" href="#other" aria-label="Permalink to &quot;Other&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>RenderScript</td><td>High-performance compute (image/GPU); deprecated</td></tr></tbody></table><hr><h2 id="kotlin" tabindex="-1">Kotlin <a class="header-anchor" href="#kotlin" aria-label="Permalink to &quot;Kotlin&quot;">​</a></h2><h3 id="numeric-literals" tabindex="-1">Numeric Literals <a class="header-anchor" href="#numeric-literals" aria-label="Permalink to &quot;Numeric Literals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Supported bases</td><td>Decimal, Binary, Hex; <strong>not</strong> Octal</td></tr></tbody></table><h3 id="visibility" tabindex="-1">Visibility <a class="header-anchor" href="#visibility" aria-label="Permalink to &quot;Visibility&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Modifiers (default public)</td><td><code>public</code>, <code>internal</code>, <code>protected</code>, <code>private</code></td></tr></tbody></table><h3 id="equality" tabindex="-1">Equality <a class="header-anchor" href="#equality" aria-label="Permalink to &quot;Equality&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>== vs ===</td><td><code>==</code> structural equality (equals); <code>===</code> referential equality</td></tr></tbody></table><h3 id="sequence" tabindex="-1">Sequence <a class="header-anchor" href="#sequence" aria-label="Permalink to &quot;Sequence&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Sequence behavior</td><td>Lazy evaluation, no intermediate collections, stateless/stateful operations</td></tr></tbody></table><h3 id="compiler-arguments" tabindex="-1">Compiler Arguments <a class="header-anchor" href="#compiler-arguments" aria-label="Permalink to &quot;Compiler Arguments&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Answer</th></tr></thead><tbody><tr><td>Valid</td><td><code>-progressive</code>, <code>-Werror</code>, <code>-g</code></td></tr><tr><td>Invalid</td><td><code>-ver</code></td></tr></tbody></table>',41)]))}const p=e(r,[["render",i]]);export{u as __pageData,p as default};
